INSERT INTO topics (id, lang, category, title, question, answer, objections, scripture, tags, difficulty, related_topics, translation_source, last_updated)
VALUES ('holy-mass', 'ceb', 'sacraments', 'Ang Santos nga Misa', 'Unsa ang gitudlo sa Simbahang Katoliko bahin sa ang santos nga misa?', '"Ang Sta. Iglesya nagtudlo nga ang Misa mao and dili duguon nga sakripisyo sa lawas ug dugo ni Cristo ubos sa bayhon sa pan ug bino. Ang Misa mao ang hingpit nga halad diha sa Bag-ong Tugon. Ang Misa mao ra nga halad ni Cristo didto sa kalbaryo sa paagi nga mao ra ang labawng pari nga naghalad ug mao ra usab ang victima nga gihalad. Didto sa Krus gihalad ni Cristo ang iyang kaugalingon sa duguon nga paagi. Diha sa Misa si Cristo mihalad sa iyang kaugalingon sa dili duguon o sacramentohanon nga paagi. Ang kapasayloan sa sala ug ang paghiuli sa grasya nahimo pinaagi sa sakripisyo didto sa krus. Ang sakripisyo sa Misa maoy pagpadangat sa maong mga grasya ngadto sa tagsatagsa. Ang Misa usa gayod ka matuod ug makita nga sakripisyo nga gitukod ni Cristo aron paghandom alang sa tanang panahon sa sakripisyo didto sa Krus, alang sa kapasayloan sa sala ug pagpapas sa silot sa sala, ug alang sa kapuslanan sa mga buhi ug sa mga patay; ug aron pagsaulog niining maong sakripisyo si Cristo nagtukod og linain nga pagkapari alang niini.\n\nSi Jesus atol sa Kataposang Panihapon mitukod ug usa ka rito sa pagsakripisyo isip handumanan ug representasyon sa iyang kamatayon sa krus. Si San Pablo miingon, “Kay nadawat ko gikan sa Ginoo ang pagtulon-an nga akong gitudlo kaninyo; nga ang Ginoong Jesus, sa gabii nga siya gibudhian, mikuha sa pan. Unya nagpasalamat siya sa Dios, ug gipikaspikas niya ang pan ug miingon, ‘Mao kini ang akong lawas nga gitugyan alang kaninyo. Buhata kini aron sa paghandom kanako.’ Human sa panihapon, gikuha niya ang kupa ug miingon, ‘Mao kini ang kupa sa Bag-ong Kasabotan nga gitiman-an sa akong dugo. Matag inom ninyo niining kupa, buhata sa paghandom kanako.” Kay sa matag kaon ninyo niining pan ug sa matag inom ninyo niining kupa, gisangyaw ninyo ang iyang kamatayon hangtod sa pagbalik niya” (1 Cor. 11:23-26). Busa, pinaagi sa pulong nga gilitok ni Jesus atol sa Kataposang Panihapon, ug pinaagi sa consagrasyon sa pan ug bino nga efecto sa maong mga pulong, Iyang gipasabot nga didto sa Krus, ang iyang dugo mahimulag sa hingpit sa iyang lawas. Iyang gihimo atubangan sa iyang mga Apostoles ang usa ka representasyon sa iyang kamatayon, ug sa iyang pag-ingon, “Buhata ninyo kini sa paghandom kanako,” Iyang gitukod ang usa ka rito sa pagsakrispisyo, usa ka handumanan sa iyang sakripisyo, nga ilang pagahimoon ug sa ilang mga sumusunod hangtod sa kataposan sa kapanahunan.\n\nSa Kataposang Panihapon, si Jesus miingon, “Mao kini ang akong lawas nga gitugyan alang kaninyo… Kining kupa mao ang Bag-ong Kasabotan sa Dios, tiniman-an sa akong dugo nga giula alang kaninyo” (Luc. 22:19). Dinhi klaro nga si Jesus naghisgot sa pagtugyan sa iyang lawas ug pag-ula sa iyang dugo. Ang kahulogan sa pulong “pagtugyan” mao ang paghalad ingon nga sakripisyo, “hangyoon ko kamo sa pagtugyan sa inyong kaugalingon ngadto sa Dios, ingon nga buhing halad” (Rom. 12:1). Busa niadtong Kataposang Panihapon gihalad ni Cristo ang iyang kaugalingon sa dili duguon nga paagi ubos sa bayhon sa pan ug bino. Dihang si Cristo mi-consagrar sa pan ug bino, Siya miingon sa mga Apostoles, “Buhata kini ninyo sa paghandom kanako.” Ang ipabuhat ni Cristo kanila mao ang iyang gibuhat niadtong Kataposang Panihapon- nga mao ang pag-consagrar sa pan ug bino aron mahimo nga iyang lawas ug dugo ug paghalad niini ingon nga sakripisyo. Busa gihimo Niya sila nga mga pari uban sa gahom sa pagbuhat sa iyang gibuhat, ug nga ilang gihatag ang maong gahom ngadto sa ilang mga sumusunod hangtod karon uban sa mando ni Cristo sa paggamit niini. Ang Misa gihalad ni Cristo pinaagi sa ministeryo sa pari. Busa si Cristo mao ang Labawng Pari sa Misa, ang pari mao ang iyang representante; apan ang pari matuod gayod nga embahador; matuod gayod nga siya mo-consagrar ug mohalad, sama mga matuod gayod nga siya mohatag og pasaylo. Siya mao ang embahador o ministro ni Cristo tungod kay gikan man ni Cristo nga iyang nadawat ang “timaan” sa pagkapari; siya ang ministro sa Simbahan, tungod kay siya mao man ang piniyalan, nga nagbuhat sa ngalan sa Simbahan ug alang sa kapuslanan sa tanan niyang mga sakop.\n\nPinaagi sa Santos nga Misa, ang pari uban sa katawhan nga nanimba, mohalad ngadto sa Dios sa labing hataas nga pagsimba, pagdayeg ug paghimaya sa Makagagahom nga Amahan (adoration), sa pagpasalamat Kaniya sa iyang kaluoy ug panalangin (thanksgiving), sa pagpangaliyupo sa Iyang panabang ug mga panalangin (petition), ug sa paghupay sa Iyang kasuko tungod sa daghan natong kalapasan ug pag-angkon sa Iyang pakighigala (propitiation), ug sa pagdawat sa iyang pasaylo sa kastigo gumikan sa sala (satisfaction)."'::jsonb, '[{"objection":"Ang Misa kada-adlaw wala na kinahanglana kay gihimo ni Jesus ang halad sa makausa ra ug alang sa tanang panahon ug walay nay pagsubli-subli (Heb. 7:27).","response":"Ang sakripisyo nga gihimo ni Cristo sa makausa ra ug alang sa tanang panahon ug wala nay pagsubli-subli mao kadtong duguon nga halad ni Cristo didto sa kalbaryo tungod kay si Cristo human siya mabanhaw dili na mamatay pag-usab (Rom. 6:9). Ang Misa dili maoy pagsubli-subli sa pagpatay ni Cristo didto sa krus, kondili maoy pagsubli sa handumanan sa iyang kamatayon sa krus, apan sa samang higayon ang iyang lawas ug dugo ang gihalad sa bayhon sa pan ug bino sa sacramentohanon nga paagi (Luc. 22:19-20)."},{"objection":"Ang bugtong halad diha sa Bag-ong Tugon mao ang kang Cristo nga halad didto sa krus. Busa kanang gihimo sa mga pari kada-adlaw dili makawagtang sa sala (Heb. 10:11).","response":"Ang gipasabot nga halad nga gihimo kada-adlaw nga dili makawagtang sa mga sala mao ang halad sa mga mananap nga gihimo sa mga pari nga judio; “kay ang dugo sa mga toro nga baka ug mga kanding dili gayod makawagtang sa mga sala” (Heb. 10:4); “Ang matag pari nga Judio nagtuman sa iyang pag-alagad adlaw-adlaw ug nagsubli-subli paghalad sa samang mga sakripisyo. Apan kining mga sakripisyoha dili gayod makawagtang sa mga sala” (Heb. 10:11). Apan ang sakrispisyo sa Santos nga Misa gipahibalo nang daan sa Daang Tugon sa halad ni Melquisedec nga pan ug bino, “Si Melquisedec nga hari sa Salem ug pari usab sa Labing Halangdong Dios nagdalag pan ug bino” (Gen. 14:18) ug sa tagna ni Propeta Malaquias labot sa hingpit nga halad nga gikahimut-an sa Dios nga himoon kada-adlaw, “Gikan sa pagsubang sa adlaw hangtod sa pagsalop niini, ang akong ngalan dako alang sa mga hentil” miingon ang Ginoo sa panon, “tungod kay ang usa ka hingpit nga halad igahalad sa akong ngalan” (Mal. 1:11); ug sa mga dili duguon nga halad nga gihimo sa mga Israelitas sama sa insenso, sa bino, ug sa pan nga walay patubo (Exo. 25:5, 29, 30)."},{"objection":"Ang balaang panagtigom o pagsimba pinaagi na sa pagwali ug pagpamati sa pulong sa Dios, mga awit ug mga pag-ampo, dili na ang Misa (Col. 3:16).","response":"Sa pagsimba sa mga Apostoles ang ilang gihimo dili kay wali lamang kondili ang pagpikaspikas sa pan; “Nagpadayon sila pagtigom kada adlaw didto sa templo, ug naghiusa sila sa pagpangaon uban ang masaya ug nangabusog ang ilang mga kasingkasing” (Buh. 2:46); “Pagka-Domingo sa gabii nagtigom kami aron pag-ambit sa balaang panihapon” (Buh. 20:7); “Ang kupa sa panalangin nga tungod niini gipasalamatan nato ang Dios- dili ba kini pagkig-ambit man nato sa dugo ni Cristo inig-inom nato gikan niining kupa? Ug dili ba pagkig-ambit man nato sa lawas ni Cristo inigkaon nato niining pan nga atong gipikaspikas” (1 Cor. 10:16). Diha sa Santos nga Misa ang mga matuohon gipakaon sa pulong sa Dios gikan sa pagbasa sa Kasulatan, pag-awit sa mga Salmo ug gipakaon usab sa langitnong kalan-on, sa pan sa kinabuhi nga mao ang unod ni Jesus (Jn. 6:51)."},{"objection":"Ang gihatag ni Jesus sa kasaulogan sa Panihapon mao ang pan ug bino pero ang sa pari, ang pan ra mao ang ipadawat sa mga tawo, busa dili kini mao (Mat. 26:26-28).","response":"Ang pan human sa consagrasyon nahimo nga buhi nga lawas ni Cristo, ug bisan og pan ra ang atong madawat wala kita makulangi kay tibuok man nga Cristo ang atong nadawat pinaagi sa gitawag og “concomittance” nga diin gani ang lawas o dugo ni Cristo anaa gayod ang tibuok nga Cristo- ang iyang unod ug dugo, kalag ug pagka-Dios. Si Jesus miingon, “Ang mokaon nining maong pan mabuhi sa dayon” (Jn. 6:58)."}]'::jsonb, '["Luc. 22:19","Rom. 12:1","Heb. 10:4","Heb. 10:11","Gen. 14:18","Mal. 1:11","Buh. 2:46","Buh. 20:7","1 Cor. 10:16","Jn. 6:58"]'::jsonb, '["holy mass"]'::jsonb, 'beginner', '[]'::jsonb, 'manual', '2026-07-23T08:13:34.047Z')
